#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> v = {1, 1, 2, 2, 3, 4, 4, 5};
    if (v.empty()) { cout << 0 << endl; return 0; }

    int slow = 0;
    for (int fast = 1; fast < (int)v.size(); fast++) {
        if (v[fast] != v[slow]) {
            slow++;
            v[slow] = v[fast];
        }
    }
    int newLen = slow + 1;
    cout << "Unique elements: " << newLen << endl;
    cout << "Array: ";
    for (int i = 0; i < newLen; i++) cout << v[i] << " ";
    cout << endl;
    return 0;
}

