#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> arr = {1, 2, 3, 1, 2, 4};

    // Step 1: XOR all elements -> xorAll = a ^ b
    int xorAll = 0;
    for (int x : arr) xorAll ^= x;

    // Step 2: Find any set bit in xorAll (a and b differ here)
    int diffBit = xorAll & (-xorAll);  // lowest set bit

    // Step 3: Partition elements by that bit, XOR each group
    int group1 = 0, group2 = 0;
    for (int x : arr) {
        if (x & diffBit)
            group1 ^= x;
        else
            group2 ^= x;
    }

    if (group1 > group2) swap(group1, group2);
    cout << "Two unique elements: " << group1 << " " << group2 << endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

bool canFinish(vector<int>& piles, int k, int h) {
    long long hours = 0;
    for (int p : piles)
        hours += (p + k - 1) / k;  // ceil(p / k)
    return hours <= h;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> piles = {3, 6, 7, 11};
    int H = 8;

    int lo = 1, hi = *max_element(piles.begin(), piles.end());
    int answer = hi;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (canFinish(piles, mid, H)) {
            answer = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    cout << "Minimum eating speed: " << answer << endl;
    return 0;
}

#include <iostream>
