using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> v = {-2, 1, -3, 4, -1, 2, 1, -5, 4};
    int maxSum = v[0], currSum = v[0];
    int start = 0, end = 0, tempStart = 0;

    for (int i = 1; i < (int)v.size(); i++) {
        if (v[i] > currSum + v[i]) {
            currSum = v[i];
            tempStart = i;
        } else {
            currSum += v[i];
        }
        if (currSum > maxSum) {
            maxSum = currSum;
            start = tempStart;
            end = i;
        }
    }

    cout << "Max sum: " << maxSum << endl;
    cout << "Subarray: index " << start << " to " << end << " -> [";
    for (int i = start; i <= end; i++) {
        cout << v[i];
        if (i < end) cout << ", ";
    }
    cout << "]" << endl;
    return 0;
}

#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<vector<int>> matrix = {{1,2,3},{4,5,6},{7,8,9}};
    int m = matrix.size(), n = matrix[0].size();

    // prefix[i][j] = sum of matrix[0..i-1][0..j-1]
    vector<vector<int>> prefix(m + 1, vector<int>(n + 1, 0));
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= n; j++)
            prefix[i][j] = matrix[i-1][j-1] + prefix[i-1][j]
                           + prefix[i][j-1] - prefix[i-1][j-1];

    // Query: sum of submatrix (r1,c1) to (r2,c2)
    int r1 = 1, c1 = 1, r2 = 2, c2 = 2;
    int sum = prefix[r2+1][c2+1] - prefix[r1][c2+1]
             - prefix[r2+1][c1] + prefix[r1][c1];
    cout << "Sum of submatrix (" << r1 << "," << c1 << ") to ("
         << r2 << "," << c2 << "): " << sum << endl;
    return 0;
}
